const svg=$('#met-svg'), out=$('#met-out'), eps=$('#met-eps'), epsv=$('#met-epsv');
let metric='e';
let cx=0, cy=0; // in math coords
const W=640, H=360;
const scale=60; // pixels per unit
function toPx(x,y){ return [W/2 + x*scale, H/2 - y*scale]; }
function toMath(px,py){ return [(px-W/2)/scale, -(py-H/2)/scale]; }

function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // grid
  const grid = SVG('g');
  for(let i=-5;i<=5;i++){
    const [px0,py0]=toPx(i,-3), [px1,py1]=toPx(i,3);
    grid.appendChild(SVG('line',{x1:px0,y1:py0,x2:px1,y2:py1,
      stroke:'var(--line)','stroke-width':0.5}));
  }
  for(let j=-3;j<=3;j++){
    const [px0,py0]=toPx(-5,j), [px1,py1]=toPx(5,j);
    grid.appendChild(SVG('line',{x1:px0,y1:py0,x2:px1,y2:py1,
      stroke:'var(--line)','stroke-width':0.5}));
  }
  // axes
  const [ax0,ay0]=toPx(-5,0), [ax1,ay1]=toPx(5,0);
  grid.appendChild(SVG('line',{x1:ax0,y1:ay0,x2:ax1,y2:ay1,stroke:'var(--mute)','stroke-width':0.8}));
  const [bx0,by0]=toPx(0,-3), [bx1,by1]=toPx(0,3);
  grid.appendChild(SVG('line',{x1:bx0,y1:by0,x2:bx1,y2:by1,stroke:'var(--mute)','stroke-width':0.8}));
  svg.appendChild(grid);

  const e = parseFloat(eps.value);
  const [pcx,pcy]=toPx(cx,cy);
  // draw the open ball
  let shape, shapeText;
  if(metric==='e'){
    shape = SVG('circle',{cx:pcx,cy:pcy,r:e*scale,
      fill:'rgba(88,196,221,0.18)',stroke:'var(--blue)','stroke-width':1.5});
    shapeText='disk';
  } else if(metric==='t'){
    // taxicab: |x-cx|+|y-cy|<e → diamond
    const pts=[
      toPx(cx+e,cy),toPx(cx,cy+e),toPx(cx-e,cy),toPx(cx,cy-e)
    ].map(p=>p.join(',')).join(' ');
    shape = SVG('polygon',{points:pts,
      fill:'rgba(255,216,102,0.18)',stroke:'var(--yellow)','stroke-width':1.5});
    shapeText='diamond (rotated square)';
  } else if(metric==='s'){
    const [x0,y0]=toPx(cx-e,cy+e), [x1,y1]=toPx(cx+e,cy-e);
    shape = SVG('rect',{x:x0,y:y0,width:x1-x0,height:y1-y0,
      fill:'rgba(131,193,103,0.18)',stroke:'var(--green)','stroke-width':1.5});
    shapeText='axis-aligned square';
  } else {
    // discrete: if e<=1, ball={center}; if e>1, all of X (draw big translucent frame)
    if(e<=1){
      shape = SVG('circle',{cx:pcx,cy:pcy,r:5,
        fill:'var(--pink)',stroke:'var(--pink)','stroke-width':1.5});
      shapeText='singleton {x}';
    } else {
      shape = SVG('rect',{x:0,y:0,width:W,height:H,
        fill:'rgba(224,122,95,0.12)',stroke:'var(--pink)','stroke-width':1.5,
        'stroke-dasharray':'6 4'});
      shapeText='all of X';
    }
  }
  svg.appendChild(shape);
  // center point
  svg.appendChild(SVG('circle',{cx:pcx,cy:pcy,r:5,fill:'var(--blue)','stroke':'#fff','stroke-width':1.5,
    style:'cursor:grab','data-drag':'1'}));
  const lbl = SVG('text',{x:pcx+8,y:pcy-8,'font-size':12,fill:'var(--ink)'});
  lbl.textContent = `x=(${cx.toFixed(2)}, ${cy.toFixed(2)})`;
  svg.appendChild(lbl);

  epsv.textContent = e.toFixed(2);
  const mNames = {e:'Euclidean', t:'taxicab', s:'sup', d:'discrete'};
  out.textContent =
    `metric: ${mNames[metric]}\n` +
    `open ball B(x,ε) of radius ε=${e.toFixed(2)}\n` +
    `shape: ${shapeText}\n\n` +
    (metric==='d'
      ? 'Discrete metric: every singleton is open, so every subset is open. This is a genuinely different topology — sequences converge only if eventually constant.'
      : 'Euclidean, taxicab, and sup metrics on ℝ² have different ball shapes but generate the SAME topology — any taxicab ball contains a smaller Euclidean ball and vice versa. Topology sees only which sets are open, not which metric you used.');
}

// dragging
let dragging=false;
svg.addEventListener('pointerdown',e=>{
  if(e.target.getAttribute('data-drag')){
    dragging=true; svg.setPointerCapture(e.pointerId);
  }
});
svg.addEventListener('pointermove',e=>{
  if(!dragging) return;
  const rect = svg.getBoundingClientRect();
  const sx = W/rect.width, sy = H/rect.height;
  const px = (e.clientX-rect.left)*sx, py=(e.clientY-rect.top)*sy;
  [cx,cy] = toMath(px,py);
  cx = Math.max(-4.5, Math.min(4.5, cx));
  cy = Math.max(-2.5, Math.min(2.5, cy));
  render();
});
svg.addEventListener('pointerup',e=>{ dragging=false; });
svg.addEventListener('pointercancel',e=>{ dragging=false; });

eps.addEventListener('input',render);
$$('[data-met]').forEach(b=>{
  b.addEventListener('click',()=>{
    metric = b.getAttribute('data-met');
    $$('[data-met]').forEach(x=>x.classList.remove('active'));
    b.classList.add('active');
    render();
  });
});
render();

