const X = ['a','b','c','d'];
// enumerate all 16 subsets as bitmasks
const subs = [];
for(let m=0;m<16;m++){
  const els = X.filter((_,i)=>m&(1<<i));
  subs.push({mask:m, name: '{'+els.join(',')+'}'||'∅', pretty: els.length? '{'+els.join(',')+'}':'∅'});
}
subs[0].pretty='∅';
const grid = $('#top-grid'), out = $('#top-out'), topSvg = $('#top-svg');
const picked = new Set();

// 4 points laid out in a row with fixed SVG coords
const PT = {a:[120,60], b:[240,60], c:[360,60], d:[480,60]};
function renderSVG(){
  while(topSvg.firstChild) topSvg.removeChild(topSvg.firstChild);
  // draw each picked subset as a translucent capsule that encloses its points
  const sortedByCount = [...picked].sort((a,b)=>{
    const ca = X.filter((_,i)=>a&(1<<i)).length;
    const cb = X.filter((_,i)=>b&(1<<i)).length;
    return cb-ca;
  });
  sortedByCount.forEach((m,idx)=>{
    const els = X.filter((_,i)=>m&(1<<i));
    if(els.length===0) return; // don't draw ∅
    if(m===15){
      // full set: big rounded rect
      topSvg.appendChild(SVG('rect',{x:60,y:22,width:540,height:76,rx:38,ry:38,
        fill:'rgba(179,157,219,0.10)',stroke:'var(--violet)','stroke-width':1}));
      return;
    }
    const xs = els.map(e=>PT[e][0]);
    const xMin=Math.min(...xs)-24, xMax=Math.max(...xs)+24;
    const pad = 14 + (idx%3)*4;
    topSvg.appendChild(SVG('rect',{x:xMin, y:60-pad, width:xMax-xMin, height:2*pad, rx:pad, ry:pad,
      fill:'rgba(88,196,221,0.12)',stroke:'var(--blue)','stroke-width':1,opacity:0.9}));
  });
  // points and labels
  X.forEach(n=>{
    const [x,y]=PT[n];
    topSvg.appendChild(SVG('circle',{cx:x,cy:y,r:7,fill:'var(--yellow)',stroke:'#fff','stroke-width':1.2}));
    const t=SVG('text',{x,y:y+22,'text-anchor':'middle','font-size':13,fill:'var(--ink)'});
    t.textContent=n; topSvg.appendChild(t);
  });
}

function renderGrid(){
  grid.innerHTML='';
  subs.forEach(s=>{
    const b = document.createElement('button');
    b.textContent = s.pretty;
    if(picked.has(s.mask)) b.classList.add('active');
    b.addEventListener('click',()=>{
      if(picked.has(s.mask)) picked.delete(s.mask);
      else picked.add(s.mask);
      renderGrid(); check(); renderSVG();
    });
    grid.appendChild(b);
  });
}
function check(){
  const arr = [...picked].sort((a,b)=>a-b);
  const hasEmpty = arr.includes(0);
  const hasX = arr.includes(15);
  // union closure
  let unionOk=true, unionFail=null;
  for(const a of arr){
    for(const b of arr){
      const u=a|b;
      if(!arr.includes(u)){ unionOk=false; unionFail=[a,b,u]; break; }
    }
    if(!unionOk) break;
  }
  // finite intersection closure
  let interOk=true, interFail=null;
  for(const a of arr){
    for(const b of arr){
      const i=a&b;
      if(!arr.includes(i)){ interOk=false; interFail=[a,b,i]; break; }
    }
    if(!interOk) break;
  }
  function nm(m){ return subs[m].pretty; }
  const lines = [];
  lines.push(`declared open: ${arr.map(nm).join(', ') || '(none)'}`);
  lines.push('');
  lines.push(`contains ∅ and X ?   ${hasEmpty && hasX ? '✓' : '✗'}`);
  lines.push(`closed under union ? ${unionOk ? '✓' : '✗  (e.g. '+nm(unionFail[0])+' ∪ '+nm(unionFail[1])+' = '+nm(unionFail[2])+' is missing)'}`);
  lines.push(`closed under ∩ ?     ${interOk ? '✓' : '✗  (e.g. '+nm(interFail[0])+' ∩ '+nm(interFail[1])+' = '+nm(interFail[2])+' is missing)'}`);
  lines.push('');
  const isTop = hasEmpty && hasX && unionOk && interOk;
  lines.push(isTop ? '★ this IS a topology on X' : '✗ not a topology');
  out.textContent = lines.join('\n');
}
function setPreset(fn){
  picked.clear();
  for(let m=0;m<16;m++) if(fn(m)) picked.add(m);
  renderGrid(); check();
}
$('#top-ex1').addEventListener('click',()=>setPreset(()=>true)); // all 16
$('#top-ex2').addEventListener('click',()=>setPreset(m=>m===0||m===15));
// Sierpiński-like: ∅, {a}, X
$('#top-ex3').addEventListener('click',()=>setPreset(m=>m===0||m===1||m===15));
// broken: ∅, {a}, {b}, X — union {a}∪{b}={a,b} missing
$('#top-ex4').addEventListener('click',()=>setPreset(m=>m===0||m===1||m===2||m===15));
$('#top-clear').addEventListener('click',()=>{ picked.clear(); renderGrid(); check(); });

setPreset(m=>m===0||m===1||m===15); // default = Sierpiński-like

