const svg=$('#hm-svg'), out=$('#hm-out'), pick=$('#hm-pick'), ySlider=$('#hm-y');
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const mode = pick.value;
  const y = parseFloat(ySlider.value);

  // Left panel: domain. Right panel: codomain.
  // Axes: left (0,300)x(0,260); right (400,700)x(0,260).
  svg.appendChild(SVG('rect',{x:0,y:0,width:700,height:260,fill:'transparent'}));

  // left label
  const lt = SVG('text',{x:10,y:18,'font-size':12,fill:'var(--mute)'});
  lt.textContent='domain X';
  svg.appendChild(lt);
  const rt = SVG('text',{x:410,y:18,'font-size':12,fill:'var(--mute)'});
  rt.textContent='codomain Y';
  svg.appendChild(rt);

  // draw domain shape
  function drawInterval(x0,y0,w, color, label){
    svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x0+w,y2:y0,stroke:color,'stroke-width':2}));
    svg.appendChild(SVG('circle',{cx:x0,cy:y0,r:3,fill:'var(--panel2)',stroke:color,'stroke-width':1.5}));
    svg.appendChild(SVG('circle',{cx:x0+w,cy:y0,r:3,fill:'var(--panel2)',stroke:color,'stroke-width':1.5}));
    const t=SVG('text',{x:x0+w/2,y:y0+25,'font-size':11,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent=label; svg.appendChild(t);
  }
  function drawCircle(cx,cy,r,color,label){
    svg.appendChild(SVG('circle',{cx,cy,r,fill:'none',stroke:color,'stroke-width':2}));
    const t=SVG('text',{x:cx,y:cy+r+22,'font-size':11,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent=label; svg.appendChild(t);
  }

