const svg=$('#cmp-svg'), out=$('#cmp-out');
let set='c', cov='sh';
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const W=700, midY=120;
  const x0=60, x1=640;
  // axis from -2 to 2
  function xOf(v){ return x0 + (v+2)/4 * (x1-x0); }
  svg.appendChild(SVG('line',{x1:x0,y1:midY,x2:x1,y2:midY,stroke:'var(--mute)','stroke-width':0.8}));
  for(let v=-2; v<=2; v+=0.5){
    svg.appendChild(SVG('line',{x1:xOf(v),y1:midY-4,x2:xOf(v),y2:midY+4,stroke:'var(--mute)','stroke-width':0.8}));
    const t=SVG('text',{x:xOf(v),y:midY+20,'font-size':10,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent=v.toFixed(1); svg.appendChild(t);
  }

  // draw set
  let setLo=0, setHi=1, setColor='var(--yellow)', setLabel='[0,1]';
  if(set==='o'){ setLo=0; setHi=1; setLabel='(0,1)'; }
  if(set==='r'){ setLo=-2; setHi=2; setColor='var(--pink)'; setLabel='ℝ (showing [-2,2])'; }
  svg.appendChild(SVG('line',{x1:xOf(setLo),y1:midY,x2:xOf(setHi),y2:midY,stroke:setColor,'stroke-width':4,opacity:0.7}));
  // endpoints mark open or closed
  const r = set==='c' ? 6 : 6;
  if(set==='c'){
    svg.appendChild(SVG('circle',{cx:xOf(0),cy:midY,r:5,fill:setColor}));
    svg.appendChild(SVG('circle',{cx:xOf(1),cy:midY,r:5,fill:setColor}));
  } else if(set==='o'){
    svg.appendChild(SVG('circle',{cx:xOf(0),cy:midY,r:5,fill:'var(--panel)',stroke:setColor,'stroke-width':1.5}));
    svg.appendChild(SVG('circle',{cx:xOf(1),cy:midY,r:5,fill:'var(--panel)',stroke:setColor,'stroke-width':1.5}));
  }
  const lblSet=SVG('text',{x:xOf(0.5),y:midY-16,'font-size':12,fill:'var(--ink)','text-anchor':'middle'});
  lblSet.textContent=setLabel; svg.appendChild(lblSet);

  // cover intervals
  let intervals=[];
  if(cov==='sh'){
    intervals.push([-0.1,0.3],[0.7,1.1]);
    for(let n=1;n<=10;n++) intervals.push([1/(n+2),1/n]);
  } else if(cov==='thirds'){
    for(let k=-2;k<=4;k++) intervals.push([k/3-0.2, k/3+0.4]);
  } else if(cov==='ints'){
    for(let n=-3;n<=3;n++) intervals.push([n-0.6,n+0.6]);
  }

  // greedy finite subcover within set [setLo, setHi]
  function greedyCover(arr, lo, hi){
    // sort by left endpoint; repeatedly pick the interval with largest right endpoint that overlaps current frontier
    const sorted = arr.slice().sort((a,b)=>a[0]-b[0]);
    let frontier = lo;
    const pick = [];
    let safety = 0;
    while(frontier<hi-1e-9 && safety<200){
      safety++;
      let best = null;
      for(const I of sorted){
        if(I[0]<=frontier+1e-9 && I[1]>frontier){
          if(!best || I[1]>best[1]) best=I;
        }
      }
      if(!best) return {ok:false, pick, stuckAt:frontier};
      pick.push(best); frontier=best[1];
    }
    return {ok:frontier>=hi-1e-9, pick};
  }
  // for open (0,1) treat lo,hi as open — need strict covering of every point in (0,1)
  // Note: for ℝ we restrict to window [-2,2].
  const res = greedyCover(intervals, setLo, setHi);

  // paint all cover intervals
  intervals.forEach((I,i)=>{
    const y = midY-45 - (i%6)*7;
    const x1 = Math.max(-2,I[0]), x2=Math.min(2,I[1]);
    if(x2<=x1) return;
    svg.appendChild(SVG('line',{x1:xOf(x1),y1:y,x2:xOf(x2),y2:y,
      stroke:'var(--line)','stroke-width':2}));
  });
  // paint chosen subcover
  (res.pick||[]).forEach((I,i)=>{
    const y = midY-45 - (i%6)*7;
    const x1 = Math.max(-2,I[0]), x2=Math.min(2,I[1]);
    svg.appendChild(SVG('line',{x1:xOf(x1),y1:y,x2:xOf(x2),y2:y,
      stroke:'var(--cyan)','stroke-width':3.5,opacity:0.9}));
  });

  // verdict
  const picked = res.pick.length;
  let lines = [];
  lines.push(`set: ${setLabel}`);
  lines.push(`cover: ${intervals.length} open intervals`);
  lines.push('');
  if(set==='c' && cov==='sh'){
    // [0,1] is covered: the (-0.1,0.3) and (0.7,1.1) leave only [0.3,0.7], which needs finitely many shrinking intervals
    lines.push(`greedy finite subcover: ${picked} intervals, covers [0,1] ✓`);
    lines.push(`[0,1] is compact: every open cover has a finite subcover.`);
  } else if(set==='o' && cov==='sh'){
    lines.push(`greedy subcover at (0,1): the shrinking family (1/(n+2),1/n) covers near 0 but any FINITE subfamily of it omits (0, 1/N) for large N.`);
    lines.push(`Finite subcover impossible ✗`);
    lines.push(`(0,1) is NOT compact.`);
  } else if(set==='c' && cov==='ints'){
    lines.push(`[0,1] ⊂ (-0.6,0.6) ∪ (0.4,1.6), so finite subcover = 2 ✓`);
  } else if(set==='c' && cov==='thirds'){
    lines.push(`covers [0,1] with ~4 intervals ✓`);
  } else if(set==='o' && (cov==='thirds'||cov==='ints')){
    lines.push(`these covers happen to admit finite subcovers even for (0,1) — but the shrinking cover shows (0,1) fails compactness in general.`);
  } else if(set==='r'){
    if(cov==='ints'){
      lines.push(`ℝ = ⋃_{n∈ℤ} (n-0.6,n+0.6), no finite subfamily reaches ±∞.`);
    } else {
      lines.push(`ℝ is unbounded, no finite set of bounded intervals can cover it.`);
    }
    lines.push(`ℝ is NOT compact (not bounded).`);
  }
  out.textContent = lines.join('\n');
}
