const svg=$('#cn-svg'), out=$('#cn-out'), gS=$('#cn-g'), gV=$('#cn-gv'), sineBtn=$('#cn-sine');
let sineMode=false;
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  const g = parseFloat(gS.value);
  gV.textContent = g.toFixed(2);
  svg.appendChild(SVG('rect',{x:0,y:0,width:700,height:280,fill:'transparent'}));

  // axes
  svg.appendChild(SVG('line',{x1:40,y1:140,x2:660,y2:140,stroke:'var(--line)','stroke-width':0.5}));

  // left disk
  const r=60;
  const c1x = 200, c1y=140;
  svg.appendChild(SVG('circle',{cx:c1x,cy:c1y,r,fill:'rgba(88,196,221,0.2)',stroke:'var(--blue)','stroke-width':2}));

  if(!sineMode){
    const c2x = 200 + 2*r + g*60, c2y=140;
    svg.appendChild(SVG('circle',{cx:c2x,cy:c2y,r,fill:'rgba(255,216,102,0.2)',stroke:'var(--yellow)','stroke-width':2}));
    let verdict;
    if(g>0.005){
      verdict = `two disks separated by gap ${g.toFixed(2)}\nDISCONNECTED: open balls around the left and right disks give U ⊔ V.\npath-components: 2 · connected components: 2`;
    } else {
      verdict = `disks touch at a single point (gap = 0)\nCONNECTED (and path-connected) — any separation U ⊔ V would have to assign the touching point to one side; neither U nor V is then open.\npath-components: 1 · connected components: 1`;
    }
    out.textContent = verdict;
  } else {
    // topologist's sine curve
    // on right half, draw the curve y = sin(1/x) for x∈(0.03,0.8), scaled, plus y-axis segment
    const ox = 400, oy = 140;
    const W=240, H=80;
    // y-axis segment
    svg.appendChild(SVG('line',{x1:ox,y1:oy-H,x2:ox,y2:oy+H,stroke:'var(--pink)','stroke-width':3}));
    const path = [];
    const N=400;
    let first = true;
    for(let i=1;i<=N;i++){
      const t = i/N;
      const x = 0.02 + t*0.8;
      const y = Math.sin(1/x);
      const px = ox + x/0.82*W;
      const py = oy - y*H*0.95;
      path.push((first?'M':'L')+' '+px.toFixed(1)+' '+py.toFixed(1));
      first=false;
    }
    svg.appendChild(SVG('path',{d:path.join(' '),fill:'none',stroke:'var(--pink)','stroke-width':1.5}));
    const t=SVG('text',{x:ox+W/2,y:oy+H+32,'font-size':12,fill:'var(--mute)','text-anchor':'middle'});
    t.textContent='topologist\u2019s sine curve: graph ∪ limit segment';
    svg.appendChild(t);
    out.textContent =
      'left disk + topologist\u2019s sine curve T (right).\n'+
      '\n'+
      'T alone: CONNECTED (closure of a connected set), NOT path-connected\n'+
      '(no continuous path from the y-axis segment to the oscillating graph).\n'+
      '→ connected components of T: 1\n'+
      '→ path-components of T: 2 (segment, graph)\n'+
      '\n'+
      'This is the canonical example showing connected ⇏ path-connected.';
  }
}
gS.addEventListener('input',render);
sineBtn.addEventListener('click',()=>{ sineMode=!sineMode; sineBtn.classList.toggle('active',sineMode); render(); });
render();

