const svg=$('#sep-svg'), out=$('#sep-out');
// concentric boxes: normal ⊂ regular ⊂ Hausdorff ⊂ T1 ⊂ T0 ⊂ all
const TIERS = [
  {id:'all',    name:'all spaces',  color:'var(--line)',   box:[30,30,640,270]},
  {id:'t0',     name:'T₀',          color:'var(--mute)',   box:[60,55,580,215]},
  {id:'t1',     name:'T₁',          color:'var(--pink)',   box:[95,80,510,165]},
  {id:'t2',     name:'T₂ Hausdorff',color:'var(--violet)', box:[130,105,440,115]},
  {id:'t3',     name:'T₃ regular',  color:'var(--cyan)',   box:[170,130,360,65]},
  {id:'t4',     name:'T₄ normal',   color:'var(--green)',  box:[215,155,270,20]},
];
const SPACES = {
  sierp:{name:'Sierpiński {0,1}',    tier:'t0', note:'distinguishes points (so T₀) but {1} is open and {0} is closed — {0} is not open, so no open separates 0 from 1. T₁ FAILS: the closure of {1} is {0,1}.'},
  cof:  {name:'ℝ with cofinite τ',    tier:'t1', note:'every singleton is closed (T₁), but any two nonempty opens have finite complement each, so they intersect. NOT Hausdorff.'},
  doub: {name:'double-origin line',   tier:'t1', note:'T₁ because points are closed, but the two origins 0₁, 0₂ cannot be separated: every open around either contains a small interval around the common axis.'},
  r:    {name:'ℝ with Euclidean τ',   tier:'t4', note:'metric space ⇒ normal ⇒ regular ⇒ Hausdorff ⇒ T₁. Second-countable, first-countable, separable — all the good stuff.'},
  disc: {name:'any metric space',     tier:'t4', note:'every metric space is normal. Disjoint closeds A,B can be separated by Urysohn-type function d(x,A)/(d(x,A)+d(x,B)).'},
  ind:  {name:'indiscrete {a,b}',     tier:'all',note:'the topology is {∅,X}. The two points have no open that separates them. FAILS T₀.'}
};
let active = null;

function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  TIERS.forEach(t=>{
    const [x,y,w,h]=t.box;
    const rect = SVG('rect',{x,y,width:w,height:h,rx:8,ry:8,
      fill:'rgba(255,255,255,0.02)',stroke:t.color,'stroke-width': active && SPACES[active].tier===t.id ? 2.5 : 1.2});
    if(active && SPACES[active].tier===t.id){
      rect.setAttribute('fill','rgba(131,193,103,0.12)');
    }
    svg.appendChild(rect);
    const txt = SVG('text',{x:x+10,y:y+16,'font-size':12,fill:t.color,'font-weight':600});
    txt.textContent=t.name;
    svg.appendChild(txt);
  });
  if(active){
    const t = TIERS.find(x=>x.id===SPACES[active].tier);
    const [bx,by,bw,bh]=t.box;
    const cx=bx+bw/2, cy=by+bh/2;
    svg.appendChild(SVG('circle',{cx,cy,r:8,fill:'var(--yellow)',stroke:'#fff','stroke-width':1.5}));
    const lbl=SVG('text',{x:cx,y:cy-14,'text-anchor':'middle','font-size':12,fill:'var(--yellow)','font-weight':600});
    lbl.textContent=SPACES[active].name;
    svg.appendChild(lbl);
  }
}

$$('[data-sp]').forEach(b=>b.addEventListener('click',()=>{
  active = b.getAttribute('data-sp');
  $$('[data-sp]').forEach(x=>x.classList.remove('active'));
  b.classList.add('active');
  const s = SPACES[active];
  const t = TIERS.find(x=>x.id===s.tier);
  out.textContent = `${s.name}\ntier: ${t.name}\n\n${s.note}`;
  render();
}));
render();

